const input = $input.first().json;

if (!input.title) throw new Error('title ist erforderlich');
if (!input.body)  throw new Error('body ist erforderlich');

const queue    = input.queue    || 'Raw';
const state    = input.state    || 'neu';
const priority = input.priority || '3 normal';

const payload = {
  UserLogin: 'root@localhost',
  Password:  $env.ZNUNY_PASSWORD || (() => { throw new Error('ZNUNY_PASSWORD nicht gesetzt'); })(),
  Ticket: {
    Title:        input.title,
    Queue:        queue,
    State:        state,
    Priority:     priority,
    CustomerUser: 'root@localhost'
  },
  Article: {
    Subject:              input.title,
    Body:                 input.body,
    ContentType:          'text/plain; charset=utf8',
    CommunicationChannel: 'Internal',
    IsVisibleForCustomer: 0
  }
};

return [{ json: { title: input.title, queue, state, priority, payload } }];

const r = $input.first().json;
const d = $('🔧 Build Ticket Payload').first().json;

const success = !r.Error && (r.TicketID != null || r.TicketNumber != null);

return [{ json: {
  success,
  ticket_id:     r.TicketID     || null,
  ticket_number: r.TicketNumber || null,
  title:         d.title,
  queue:         d.queue,
  state:         d.state,
  error: r.Error ? `${r.Error.ErrorCode}: ${r.Error.ErrorMessage}` : null
} }];
